async function seed() {
  console.log('Seeding database…')

  // Upsert all decks (HSK1 + HSK2 + HSK3)
  const allDecks = [...HSK1_DECK, ...HSK2_DECK, ...HSK3_DECK]
  const insertedDecks = await db
    .insert(decks)
    .values(allDecks)
    .onConflictDoUpdate({ target: decks.name, set: { description: decks.description } })
    .returning({ id: decks.id, name: decks.name })

  const deckMap = Object.fromEntries(insertedDecks.map((d) => [d.name, d.id]))

  // Deduplicate by simplified form before inserting (across all word lists)
  const seen = new Set<string>()
  const allWords = [...HSK1_WORDS, ...HSK2_WORDS, ...HSK3_WORDS]
  const wordRows = allWords
    .filter((w) => {
      if (seen.has(w.simplified)) return false
      seen.add(w.simplified)
      return true
    })
    .map((w) => ({
      simplified: w.simplified,
      traditional: w.traditional,
      pinyin: w.pinyin,
      tones: w.tones,
      meaning: w.meaning,
      deckId: deckMap[w.deck],
    }))

  await db
    .insert(words)
    .values(wordRows)
    .onConflictDoNothing()

  console.log(`Seeded ${insertedDecks.length} decks and ${wordRows.length} words.`)
}

seed().catch((err) => {
  console.error('Seed failed:', err)
  process.exit(1)
})
